#include<bits/stdc++.h>
using namespace std;
struct node{
    string t,d;
}a[1005];
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        cin>>a[i].t>>a[i].d;
    }
    for(int i=1;i<=m;i++){
        string tt,aa,bb,cc,dd;
        cin>>tt>>aa>>bb>>cc>>dd;
        for(int j=1;j<=n;j++){
            if(a[j].t==tt){
                if(a[j].d==aa){
                    cout<<"A\n";
                }if(a[j].d==bb){
                    cout<<"B\n";
                }if(a[j].d==cc){
                    cout<<"C\n";
                }if(a[j].d==dd){
                    cout<<"D\n";
                }
            }
        }
    }
  return 0;
}
